import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [text, setText] = useState("");
  const [braille, setBraille] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!text) {
      setBraille("");
      return;
    }

    const timer = setTimeout(async () => {
      try {
        setLoading(true);

        const res = await axios.post(
          "http://localhost:5001/translate",
          { text }
        );

        setBraille(res.data.flippedBraille);
      } catch (err) {
        console.error(err);
        setBraille("Error connecting to backend");
      } finally {
        setLoading(false);
      }
    }, 300);

    return () => clearTimeout(timer);
  }, [text]);

  return (
    <div style={styles.container}>
      <h1>Braille Translator</h1>

      <textarea
        placeholder="Enter text..."
        value={text}
        onChange={(e) => setText(e.target.value)}
        style={styles.textarea}
      />

      <textarea
        placeholder="Flipped Braille output..."
        value={loading ? "Translating..." : braille}
        readOnly
        style={styles.textarea}
      />
    </div>
  );
}

const styles = {
  container: {
    maxWidth: "800px",
    margin: "40px auto",
    fontFamily: "Arial"
  },
  textarea: {
    width: "100%",
    height: "120px",
    marginTop: "20px",
    padding: "10px",
    fontSize: "16px"
  }
};

export default App;
